class Solution {
public:
    string breakPalindrome(string palindrome) {
        int n = palindrome.length();
        for (int i = 0; i < n / 2; ++i) {
            if (palindrome[i] != 'a') {
                return palindrome.substr(0, i) + 'a' + palindrome.substr(i + 1);
            }
        }
        return "";
    }
};
```
